const cp = require('child_process');
const fs = require('fs');
const code = ($json.body && $json.body.code) || '';
if (!code) return [{json:{output:'Falta code'}}];
const tmpFile = '/home/lucy-ubuntu/Escritorio/NIN/data/tmp_script_' + Date.now() + '.py';
fs.writeFileSync(tmpFile, code);
try {
  const out = cp.execSync('docker run --rm -v ' + tmpFile + ':' + tmpFile + ' python:3.9-slim python ' + tmpFile, {timeout:30000}).toString();
  try{fs.unlinkSync(tmpFile)}catch(e){}
  return [{json:{output:'OK:\n' + (out||'(sin output)')}}];
} catch(e) {
  try{fs.unlinkSync(tmpFile)}catch(err){}
  return [{json:{output:'Error:\n'+(e.stderr?e.stderr.toString():e.message)}}];
}
